--v5.5 - for any errors or question my discord: kamuworl
--[[
Moves = {
    "Anger Rush",
    "Flash Strike",
    "Chain Destructo Disk",
	"Deadly Dance",
    "Flash Skewer"
}

Settings = {

   -- Queue/Earth world
    FarmEarth = false; --use the earth pads
    RejoinPads = 170; --rejoin in queue and earth
    HardTOP = false; --[ false: NormalTOP ] [ true: HardTOP ]
	SelectPad = 8; --queue 1 to 8
	ExtraTime1 = 0; --for queue and earth
	ExtraTime2 = 0; --for tops
-----------------------------------------------------

   -- TOP world
    RejoinTOP = 600; --sends you back to queue/earth
	NPCsDistance = 4.2; --your distance to the npcs
    KiTracker = true; --recommend using "Chain Destructo Disk" first go for pump then use ki tracker (you don’t need to add melee for pump if you dont want to and don’t use target attacks)
    PetTime = 10; --pet (B)
	AntiLeech = false; --if a player enters your top it sends you back to queue/earth
	WhiteListLeech = {"asasd", "asdasdd"}; --allowed users for antileech add as many as you want
    UsePunch = true; --use normal hits when your ki is low
    AutoBlock = false; --only when your ki is above 20% keep block on at all times (f)
   -- | Zenoh-Sama
    AutoWish = true;
    ChooseWish = "Zenni"; --[ Normal TOP: "Zenni"  "Cap"  "EXP"  "Prestige" ] [ Hard TOP: "God"  "Death"  "Nothing" ]
    ZenohChatDelay = .3; --.3 for fast
   -- | Transformations
    Transformations = false; --for races that charge ki
    ChargeTime = 3; --charge timer
    FormType = "h"; --"g" or "h"
    DroidForm = true; --(android race only) use direct current when your ki reaches 70%
    UseGod = true; --use god when your health and ki are low
    FastGod = false;  --lower your power to get to god faster
    MinPower = 5; --from 5 to 100, the lower it is the more health fastgod drains (adjust in steps of 5)
-----------------------------------------------------

   -- beans/jars buyer
    AutoBuy = false;
    ZenniGoal = 900000; --zenni required to go buy
	SenzuChatDelay = .3; --.3 for fast
    BeansOrJars = "Jars"; --[ "Beans", "Jars" ]
    Amount = 80; --[ "8", "80" ]
    BuyType = "Red"; --[ "Blue", "Green", "Red", "Yellow" ]
-----------------------------------------------------

   -- Others
    DuoMode = false,
	MainAcc = "zomvie2x"; --the account with the most damage / the one everyone will tp to
	AltAcc = {"kamuworl", "asdasd"}; --the accounts that just spam jars, add as many as you want
	WaitAccsTop = false; --if one of the accounts doesn’t make it into the top, it sends you back
   -- |
	FPSBoost = true; --poop graphics
-----------------------------------------------------
}
]]
